// GlowStatCard — glass card with colored glow border
function GlowStatCard({ value, label, sub, color, glowIntensity = 0.3 }) {
  const glowHex = Math.round(glowIntensity * 255).toString(16).padStart(2, '0');
  const glowStyle = color
    ? `border-color: ${color}; box-shadow: 0 0 20px ${color}${glowHex}, inset 0 1px 0 rgba(255,255,255,0.1)`
    : undefined;

  return div({
    class: css('d-glass _p5 _r3 _flex _col _gap2 _border _bc[transparent] _trans[box-shadow_0.3s,border-color_0.3s]'),
    style: glowStyle
  },
    span({ class: css('_text[2.75rem] _bold _lh[1]'), style: color ? `color:${color}` : undefined }, value),
    span({ class: css('_textbase _fgfg _bold') }, label),
    span({ class: css('_textsm _fgmuted _lh[1.4]') }, sub)
  );
}

// SecondaryStatsRow — inline stats with dot separators
function SecondaryStatsRow({ stats }) {
  return div({ class: css('d-glass _p4 _r3 _flex _aic _jcc _gap8') },
    ...stats.flatMap((s, i) => [
      i > 0 ? span({ class: css('_fgmuted/30') }, '·') : null,
      div({ class: css('_flex _aic _gap2') },
        span({ class: css('_textxl _bold _fgfg') }, s.value),
        span({ class: css('_textsm _fgmuted') }, s.label)
      )
    ]).filter(Boolean)
  );
}

// Main layout
function BentoAsymmetricGlow({ hero, heroStats, secondaryStats, features }) {
  return section({ class: css('_py24 _px6') },
    div({ class: css('_mw[1100px] _mx[auto] _flex _col _gap6') },
      // Asymmetric bento grid
      div({ class: css('_grid _gc1 _lg:gc[1fr_1fr] _gap6') },
        // Hero card (spans 2 rows)
        div({ class: css('_lg:row[span_2]') },
          Card({ class: css('d-glass _h100') },
            Card.Body({ class: css('_flex _col _gap4 _h100 _jcsb') },
              div({ class: css('_flex _col _gap4') },
                span({ class: css('_fgprimary _textxs _uppercase _tracking[0.1em] _bold _self[start]') }, hero.chip),
                h2({ class: css('_heading3 _fgfg') }, hero.title),
                p({ class: css('_fgmuted _lh[1.6] _textsm') }, hero.description)
              ),
              hero.terminal
            )
          )
        ),
        // Hero stats with glow
        div({ class: css('_grid _gc2 _gap4') }, ...heroStats.map(s => GlowStatCard(s))),
        // Secondary stats row
        SecondaryStatsRow({ stats: secondaryStats })
      ),
      // Features row
      div({ class: css('_grid _gc1 _md:gc3 _gap6 _pt6 _borderT _bcborder') },
        ...features.map(f =>
          div({ class: css('_flex _aic _gap3') },
            icon(f.icon, { class: css('_fgprimary _w5 _h5') }),
            div({ class: css('_flex _col') },
              span({ class: css('_textbase _fgfg _bold') }, f.title),
              span({ class: css('_textsm _fgmuted') }, f.sub)
            )
          )
        )
      )
    )
  );
}

